INSERT INTO skill_paths (skill, duration, phases) VALUES
  ('Frontend Web Development',            '4–6 months', '["Learn HTML, CSS & responsive design basics","Master JavaScript (ES6+) and DOM manipulation","Build projects with React (components, hooks, routing)","Learn state management, testing (Jest/Cypress) & TypeScript","Optimize performance, accessibility & deploy to production"]'),
  ('Backend Web Development',             '4–6 months', '["Learn a server-side language (Node.js or Python)","Understand REST API design & HTTP fundamentals","Work with databases (SQL + NoSQL) and ORMs","Implement authentication, authorization & security best practices","Build, test & deploy a production-ready API"]'),
  ('Full-Stack Web Development',          '6–9 months', '["Learn HTML, CSS, JavaScript & responsive design","Build server-side APIs with Node.js/Express or Python/Django","Connect frontend to backend; manage databases (SQL & NoSQL)","Add auth, testing, state management & TypeScript","Deploy full-stack apps with CI/CD & cloud hosting"]'),
  ('Mobile App Development',              '5–7 months', '["Learn mobile UI/UX principles & platform guidelines","Pick a framework (React Native or Flutter) & learn basics","Build screens, navigation & connect to REST APIs","Handle state management, local storage & push notifications","Test, optimize performance & publish to app stores"]'),
  ('Game Development',                    '6–9 months', '["Learn game design fundamentals & choose an engine (Unity/Godot)","Understand 2D/3D graphics, physics & game loops","Script gameplay mechanics, AI & player interactions","Design levels, UI, audio integration & polish","Test, optimize & publish your game"]'),
  ('API Development',                     '3–5 months', '["Understand HTTP, REST principles & API design patterns","Build CRUD endpoints with Node.js/Express or FastAPI","Add authentication (JWT/OAuth), rate limiting & validation","Write API documentation (OpenAPI/Swagger) & versioning","Test, monitor & deploy APIs to production"]'),
  ('Database Administration',             '4–6 months', '["Learn relational database fundamentals & SQL","Design schemas, normalize data & write complex queries","Manage indexes, query optimization & performance tuning","Set up backups, replication & disaster recovery","Implement security, monitoring & cloud-managed databases"]'),
  ('Software Testing',                    '3–5 months', '["Understand testing fundamentals & the testing pyramid","Write unit tests with Jest, PyTest or similar frameworks","Learn integration & end-to-end testing (Cypress, Selenium)","Practice test-driven development (TDD) & BDD","Set up CI test pipelines, coverage reports & quality gates"]'),
  ('Quality Assurance (QA)',              '3–5 months', '["Learn QA fundamentals, SDLC & defect lifecycle","Create test plans, test cases & traceability matrices","Perform manual testing: functional, regression & exploratory","Learn automation basics with Selenium or Playwright","Integrate QA into CI/CD pipelines & report metrics"]'),
  ('Blockchain Development',              '5–7 months', '["Understand blockchain fundamentals, consensus & cryptography","Learn Solidity & write basic smart contracts","Build and test dApps on Ethereum testnets","Integrate wallets (MetaMask), Web3.js/ethers.js & IPFS","Audit smart contracts & deploy to mainnet"]'),
  ('Smart Contract Development',          '4–6 months', '["Learn Solidity syntax, data types & contract structure","Understand EVM, gas optimization & storage patterns","Write, compile & deploy contracts with Hardhat/Foundry","Test contracts thoroughly & handle upgradability patterns","Audit for vulnerabilities & deploy to mainnet"]'),
  ('Data Entry',                          '1–2 months', '["Learn typing skills, accuracy techniques & keyboard shortcuts","Master spreadsheet tools (Excel/Google Sheets)","Understand data formats, validation & cleaning basics","Practice CRM/database entry & form-based data capture","Improve speed, build QA checklists & automate repetitive tasks"]'),
  ('Data Scraping',                       '2–3 months', '["Learn HTML/CSS structure & how websites serve data","Use Python with requests & BeautifulSoup for basic scraping","Handle pagination, AJAX & dynamic content (Selenium/Playwright)","Work with APIs, JSON parsing & data storage (CSV, databases)","Respect robots.txt, rate-limit ethically & schedule scrapers"]'),
  ('Data Analysis',                       '3–5 months', '["Learn statistics fundamentals & analytical thinking","Master Excel/Google Sheets for data manipulation","Use Python (pandas, NumPy) or R for data wrangling","Create dashboards & reports with Tableau or Power BI","Present insights, tell data stories & inform decisions"]'),
  ('Data Science',                        '6–9 months', '["Learn Python, statistics & probability fundamentals","Master data wrangling with pandas, NumPy & SQL","Explore data visualization (Matplotlib, Seaborn, Plotly)","Build ML models: regression, classification & clustering","Deploy models, run experiments & communicate findings"]'),
  ('Data Visualization',                  '2–4 months', '["Learn visual design principles & chart selection","Master a visualization tool (Tableau, Power BI or D3.js)","Connect to data sources & create interactive dashboards","Design compelling data stories & presentations","Publish dashboards, gather feedback & iterate"]'),
  ('Machine Learning',                    '6–9 months', '["Learn Python, linear algebra, statistics & probability","Master scikit-learn: regression, classification & clustering","Understand model evaluation, cross-validation & hyperparameter tuning","Explore deep learning with TensorFlow or PyTorch","Deploy models with APIs, monitor drift & retrain"]'),
  ('Artificial Intelligence Development', '6–9 months', '["Learn Python, math foundations & AI history","Explore search algorithms, knowledge representation & logic","Build ML models: supervised, unsupervised & reinforcement learning","Work with NLP, computer vision or generative AI","Deploy AI systems, evaluate ethics & scale in production"]'),
  ('Prompt Engineering',                  '1–2 months', '["Understand LLM fundamentals & how prompts are processed","Learn prompting techniques: zero-shot, few-shot & chain-of-thought","Practice prompt iteration, evaluation & output formatting","Explore system prompts, tool use & retrieval-augmented generation","Build prompt libraries, test at scale & optimize for production"]'),
  ('Workflow Automation',                 '2–4 months', '["Identify repetitive tasks & map current workflows","Learn a no-code tool (Zapier, Make, Power Automate)","Connect apps, build multi-step automations & handle errors","Add conditional logic, loops & data transformations","Monitor automations, measure ROI & optimize over time"]'),
  ('Robotic Process Automation (RPA)',    '3–5 months', '["Understand RPA concepts, use cases & tool landscape","Learn a platform (UiPath, Automation Anywhere or Blue Prism)","Build attended & unattended bots for common workflows","Handle exceptions, logging & orchestration","Deploy bots, monitor performance & maintain at scale"]'),
  ('Cloud Computing',                     '4–6 months', '["Understand cloud models (IaaS, PaaS, SaaS) & providers","Learn core services: compute, storage, networking & IAM","Deploy applications on AWS, Azure or GCP","Set up monitoring, logging & cost management","Prepare for a cloud certification (AWS CCP, AZ-900, etc.)"]'),
  ('Cloud Architecture',                  '5–7 months', '["Review cloud fundamentals & well-architected framework","Design high-availability, fault-tolerant architectures","Implement networking (VPC, subnets, load balancers)","Plan security, compliance & disaster recovery strategies","Optimize cost, performance & prepare for Solutions Architect cert"]'),
  ('DevOps',                              '5–7 months', '["Learn Linux, scripting (Bash/Python) & Git workflows","Understand CI/CD concepts & set up pipelines (GitHub Actions, Jenkins)","Containerize apps with Docker & orchestrate with Kubernetes","Implement Infrastructure as Code (Terraform, CloudFormation)","Set up monitoring, logging & incident response (Prometheus, Grafana)"]'),
  ('Server Administration',              '4–6 months', '["Learn Linux/Windows Server fundamentals & the command line","Configure web servers (Nginx/Apache), DNS & networking","Manage users, permissions, SSH & firewall rules","Set up backups, monitoring & log management","Harden security, automate maintenance & handle incidents"]'),
  ('Cybersecurity',                       '5–7 months', '["Learn security fundamentals, CIA triad & threat landscape","Understand networking, protocols & common vulnerabilities","Practice with security tools (Wireshark, Nmap, Burp Suite)","Learn offensive basics: scanning, exploitation & reporting","Study compliance frameworks & prepare for Security+ or CEH"]'),
  ('Ethical Hacking',                     '5–7 months', '["Learn networking, Linux & security fundamentals","Set up labs (Kali Linux, VMs) & practice reconnaissance","Exploit vulnerabilities: web apps, networks & systems","Master tools: Metasploit, Burp Suite, Nmap & Wireshark","Write professional pen-test reports & pursue OSCP/CEH"]'),
  ('Network Engineering',                 '5–7 months', '["Learn OSI model, TCP/IP & networking fundamentals","Configure routers, switches & VLANs (Cisco Packet Tracer/GNS3)","Implement subnetting, routing protocols (OSPF, BGP) & ACLs","Set up wireless networks, VPNs & network security","Monitor, troubleshoot & prepare for CCNA certification"]'),
  ('IT Support',                          '2–4 months', '["Learn computer hardware, OS basics & troubleshooting","Understand networking fundamentals & connectivity issues","Practice help-desk scenarios: ticketing, remote support & escalation","Learn Active Directory, user management & security basics","Prepare for CompTIA A+ or Google IT Support certification"]'),
  ('User Interface (UI) Design',          '3–5 months', '["Learn design principles: layout, typography & color theory","Master Figma or Sketch for UI mockups & components","Build design systems: tokens, components & documentation","Create responsive designs & interactive prototypes","Conduct usability testing, iterate & hand off to developers"]'),
  ('User Experience (UX) Design',         '4–6 months', '["Understand UX fundamentals, design thinking & user-centered design","Conduct user research: interviews, surveys & persona creation","Create user flows, wireframes & information architecture","Build interactive prototypes in Figma & run usability tests","Analyze results, iterate designs & build a UX portfolio"]'),
  ('Graphic Design',                      '4–6 months', '["Learn design principles: composition, color & typography","Master Adobe Photoshop & Illustrator (or Affinity tools)","Create real projects: posters, social media graphics & layouts","Learn print design: bleeds, CMYK, export settings","Build a portfolio & learn client communication"]'),
  ('Brand Identity Design',               '3–5 months', '["Study branding fundamentals, brand strategy & positioning","Learn logo design process: research, sketching & refinement","Build brand identity systems: colors, typography & patterns","Create brand guidelines documents & asset libraries","Present brand work to stakeholders & build your portfolio"]'),
  ('Illustration',                        '4–6 months', '["Learn drawing fundamentals: line, shape, perspective & value","Practice digital illustration in Procreate, Photoshop or Illustrator","Develop your style through daily sketching & studies","Create themed illustration series & editorial pieces","Build an illustration portfolio & find freelance opportunities"]'),
  ('Video Editing',                       '3–5 months', '["Learn video editing basics & storytelling through cuts","Master an NLE (Premiere Pro, DaVinci Resolve or Final Cut)","Edit real projects: vlogs, short films & social content","Add transitions, effects, titles & color correction","Export for various platforms, build a reel & manage projects"]'),
  ('Color Grading',                       '2–4 months', '["Understand color theory, color spaces & scopes (waveform, vectorscope)","Learn DaVinci Resolve color grading tools & workflows","Practice primary corrections: exposure, white balance & contrast","Apply secondary corrections, masks & creative LUTs","Grade a full project, match shots & build a showreel"]'),
  ('Motion Graphics',                     '4–6 months', '["Learn animation principles & motion design fundamentals","Master After Effects: keyframes, easing & compositions","Create text animations, lower thirds & transitions","Integrate with Illustrator/Photoshop & use expressions","Build complex projects, render & create a motion reel"]'),
  ('2D Animation',                        '5–7 months', '["Learn 12 principles of animation & timing","Master a 2D tool (Toon Boom, Adobe Animate or OpenToonz)","Practice walk cycles, lip sync & character acting","Storyboard, create animatics & animate short scenes","Produce a short animated piece & build your reel"]'),
  ('3D Modeling',                         '5–7 months', '["Learn 3D fundamentals & choose a tool (Blender, Maya or 3ds Max)","Practice hard-surface modeling: shapes, extrusions & booleans","Model organic forms: characters, creatures & sculpting","UV unwrap, texture & apply materials (Substance Painter)","Render, light scenes & build a 3D portfolio"]'),
  ('3D Animation',                        '6–9 months', '["Learn animation principles applied to 3D (timing, spacing, arcs)","Master rigging basics & understand character rigs","Animate walk cycles, actions & lip sync in your 3D tool","Create camera animation, cinematics & scene layout","Polish animations, render & compile a demo reel"]'),
  ('Audio Editing',                       '2–3 months', '["Learn audio fundamentals: waveforms, sample rates & bit depth","Master a DAW (Audacity, Adobe Audition or Logic Pro)","Practice editing: cutting, fading, noise reduction & normalization","Mix multi-track audio: levels, panning & EQ","Export for podcasts, video & streaming; build a portfolio"]'),
  ('Sound Design',                        '4–6 months', '["Learn sound theory, acoustics & psychoacoustics","Record & manipulate sounds: foley, field recording & synthesis","Design sound effects for film, games or interactive media","Layer, process & mix sound elements in a DAW","Build a sound library & showcase reel"]'),
  ('Music Production',                    '5–7 months', '["Learn music theory: scales, chords, rhythm & song structure","Master a DAW (Ableton, FL Studio or Logic Pro)","Create beats, melodies & arrangements","Mix tracks: EQ, compression, reverb & stereo imaging","Master your tracks & distribute on streaming platforms"]'),
  ('Digital Marketing',                   '3–5 months', '["Understand digital marketing channels & strategy frameworks","Learn Google Ads, Meta Ads & campaign management","Master analytics: Google Analytics, UTM tracking & KPIs","Create landing pages, A/B test & optimize conversions","Build a marketing plan, measure ROI & get certified"]'),
  ('Social Media Marketing',              '2–4 months', '["Understand platform algorithms, audiences & content types","Create a content strategy & editorial calendar","Learn scheduling tools (Buffer, Hootsuite) & community management","Run paid social campaigns & analyze performance","Grow engagement, report results & refine strategy"]'),
  ('Content Marketing',                   '3–5 months', '["Learn content marketing strategy & buyer''s journey mapping","Research topics, keywords & create a content calendar","Write blog posts, guides & lead magnets","Distribute content: SEO, email, social & repurposing","Measure performance: traffic, leads & conversions"]'),
  ('Email Marketing',                     '2–3 months', '["Learn email marketing fundamentals & deliverability basics","Choose a platform (Mailchimp, ConvertKit or SendGrid)","Build lists, create segments & design responsive emails","Write compelling subject lines, CTAs & automated sequences","Analyze open/click rates, A/B test & optimize campaigns"]'),
  ('SEO (Search Engine Optimization)',    '3–5 months', '["Learn how search engines work & SEO fundamentals","Master on-page SEO: keywords, meta tags, headings & content","Implement technical SEO: site speed, mobile, crawlability & schema","Build backlinks through outreach, guest posts & digital PR","Track rankings, analyze traffic & refine your SEO strategy"]'),
  ('SEM (Search Engine Marketing)',       '2–4 months', '["Understand paid search fundamentals & Google Ads platform","Set up campaigns: keywords, ad groups, bids & budgets","Write effective ad copy & use ad extensions","Optimize quality score, CTR & conversion tracking","Analyze performance, scale campaigns & manage ROAS"]'),
  ('Affiliate Marketing',                 '2–4 months', '["Understand affiliate marketing models & revenue structures","Choose a niche, find affiliate programs & networks","Build a content platform (blog, YouTube or social)","Create honest reviews, comparisons & promotional content","Track conversions, optimize funnels & scale earnings"]'),
  ('E-commerce Management',               '3–5 months', '["Understand e-commerce models & choose a platform (Shopify, WooCommerce)","Set up a store: products, categories, payments & shipping","Optimize product pages, photos & descriptions for conversions","Drive traffic: SEO, ads, email marketing & social media","Manage orders, customer service & analyze store analytics"]'),
  ('Dropshipping',                        '2–3 months', '["Understand the dropshipping model, pros, cons & legalities","Research niches, find winning products & reliable suppliers","Set up a Shopify store with apps (DSers, Oberlo alternatives)","Launch Facebook/Google ad campaigns & test products","Optimize for profit: scale winners, cut losers & automate fulfillment"]'),
  ('Technical Writing',                   '3–5 months', '["Learn technical writing principles & audience analysis","Master documentation formats: guides, API docs & tutorials","Use tools: Markdown, docs-as-code, Swagger & MkDocs","Write clear procedures, troubleshoot guides & release notes","Edit for clarity, maintain docs & build a writing portfolio"]'),
  ('Copywriting',                         '2–4 months', '["Learn copywriting fundamentals: AIDA, PAS & persuasion psychology","Study great copy: headlines, landing pages & email sequences","Practice writing: ads, product descriptions & sales pages","Learn conversion optimization & A/B testing copy variants","Build a swipe file, create samples & land clients"]'),
  ('Content Writing',                     '2–4 months', '["Understand content formats: blogs, articles, guides & white papers","Learn research techniques, outlining & SEO writing basics","Develop your writing voice, style & editing process","Write for different industries & platforms","Build a portfolio, pitch editors & manage writing projects"]'),
  ('Blog Writing',                        '2–3 months', '["Learn blog structure: headlines, intros, subheadings & CTAs","Research topics using keyword tools & audience insights","Write engaging, SEO-optimized blog posts","Edit, format & add visuals for readability","Publish, promote & analyze post performance"]'),
  ('Scriptwriting',                       '3–5 months', '["Learn script formats: screenplays, video scripts & podcast scripts","Study story structure: three-act, hero''s journey & scene writing","Write short scripts: ads, explainers & YouTube videos","Revise with feedback, polish dialogue & pacing","Build a script portfolio & pitch to producers/creators"]'),
  ('Proofreading',                        '1–2 months', '["Learn grammar, punctuation & style guide fundamentals (AP, Chicago)","Practice spotting errors: typos, consistency & formatting issues","Use proofreading tools (Grammarly, PerfectIt) as aids, not crutches","Proofread real documents: articles, reports & marketing copy","Build a checklist, set rates & find freelance proofreading work"]'),
  ('Translation',                         '3–6 months', '["Strengthen bilingual skills & understand translation theory","Learn CAT tools (SDL Trados, MemoQ or Smartcat)","Practice translating: general, technical & creative texts","Understand localization, cultural adaptation & terminology management","Build a translation portfolio & join freelance platforms"]'),
  ('Project Management',                  '3–5 months', '["Learn PM fundamentals: scope, time, cost & quality","Understand methodologies: Waterfall, Agile & hybrid approaches","Master PM tools: Jira, Asana, Trello or MS Project","Practice planning: WBS, Gantt charts, risk & stakeholder management","Lead a project end-to-end & prepare for PMP/CAPM certification"]'),
  ('Agile & Scrum',                       '2–3 months', '["Understand Agile values, principles & the Agile Manifesto","Learn Scrum framework: roles, events & artifacts","Practice sprint planning, daily standups & retrospectives","Use Jira or similar tools for backlog management","Prepare for Professional Scrum Master (PSM) certification"]'),
  ('Product Management',                  '4–6 months', '["Learn product thinking, user-centric design & market analysis","Define product vision, strategy & roadmap","Prioritize features with frameworks (RICE, MoSCoW, Kano)","Work cross-functionally: engineering, design & marketing","Launch products, measure success metrics & iterate"]'),
  ('Business Analysis',                   '3–5 months', '["Understand BA role, BABOK framework & business needs analysis","Learn requirements elicitation: interviews, workshops & observation","Document requirements: user stories, use cases & process models","Create wireframes & prototypes to validate solutions","Support UAT, trace requirements & prepare for CBAP/ECBA"]'),
  ('Financial Analysis',                  '3–5 months', '["Learn accounting basics, financial statements & ratios","Master Excel for financial modeling & scenario analysis","Understand valuation methods: DCF, comparables & precedents","Build financial models: budgets, forecasts & dashboards","Present analysis to stakeholders & prepare for CFA Level I"]'),
  ('Accounting',                          '4–6 months', '["Learn double-entry bookkeeping & chart of accounts","Understand financial statements: income, balance sheet & cash flow","Master accounting software (QuickBooks, Xero or SAP)","Learn tax fundamentals, payroll & regulatory compliance","Prepare for CPA/ACCA or equivalent certification"]'),
  ('Bookkeeping',                         '2–3 months', '["Learn bookkeeping basics: debits, credits & ledgers","Master QuickBooks or Xero for daily transactions","Reconcile bank statements & manage accounts receivable/payable","Generate financial reports & assist with month-end close","Maintain organized records & support tax preparation"]'),
  ('Entrepreneurship',                    '3–6 months', '["Develop business ideas & validate with market research","Create a lean business plan & define your value proposition","Build an MVP, test with real users & iterate","Learn basics of funding: bootstrapping, pitch decks & investors","Launch, acquire customers & build sustainable growth"]'),
  ('Sales & Negotiation',                 '2–4 months', '["Learn sales fundamentals: pipeline, prospecting & qualifying leads","Master communication: active listening, objection handling & closing","Practice negotiation techniques: BATNA, anchoring & win-win","Use CRM tools (Salesforce, HubSpot) for pipeline management","Develop a personal sales playbook & track KPIs"]'),
  ('Customer Service',                    '1–3 months', '["Understand customer service principles & communication skills","Learn support tools: ticketing systems, live chat & phone etiquette","Practice handling complaints, escalations & difficult customers","Master product knowledge & build FAQ/knowledge bases","Measure satisfaction (CSAT, NPS) & continuously improve"]'),
  ('Virtual Assistance',                  '1–3 months', '["Learn core VA skills: email, calendar & task management","Master productivity tools: Google Workspace, Notion & Slack","Practice scheduling, travel booking & document preparation","Develop communication, time management & prioritization","Find VA clients, set boundaries & manage multiple accounts"]'),
  ('Human Resources (HR)',                '3–5 months', '["Learn HR fundamentals: employment law, policies & compliance","Understand talent management: onboarding, L&D & performance reviews","Master HR tools: HRIS systems, applicant tracking & payroll basics","Learn employee relations, conflict resolution & culture building","Stay current with labor laws & pursue SHRM/PHR certification"]'),
  ('Recruitment & Talent Acquisition',    '2–4 months', '["Understand recruitment lifecycle & sourcing strategies","Learn Boolean search, LinkedIn Recruiter & job board management","Screen candidates: resume review, phone screens & assessments","Conduct structured interviews & evaluate culture fit","Manage offers, negotiate & improve time-to-hire metrics"]'),
  ('Public Speaking',                     '2–4 months', '["Overcome fears & build confidence through practice","Learn speech structure: opening, body & closing techniques","Master delivery: voice projection, pacing & body language","Practice with real audiences or Toastmasters","Develop specialty talks, build a speaker profile & seek engagements"]'),
  ('Leadership & Management',            '3–5 months', '["Understand leadership styles, emotional intelligence & self-awareness","Learn team management: delegation, feedback & motivation","Practice conflict resolution, coaching & mentoring","Set vision, align goals & drive organizational change","Develop executive presence & continuous leadership growth"]'),
  ('Personal Branding',                   '2–3 months', '["Define your unique value proposition & target audience","Build your online presence: LinkedIn, portfolio & personal site","Create consistent content: posts, articles & videos","Network strategically: events, communities & collaborations","Monitor your brand, gather feedback & refine messaging"]'),
  ('Resume & Career Building',            '1–2 months', '["Audit your skills & define career goals","Write a compelling resume tailored to target roles","Optimize your LinkedIn profile & online presence","Practice interviewing: behavioral, technical & case questions","Build a career development plan & grow your network"]'),
  ('Teaching & Tutoring',                 '2–4 months', '["Understand learning theories & instructional design basics","Plan lessons: objectives, activities & assessments","Master communication: explaining concepts clearly & engaging learners","Use digital tools: whiteboards, LMS & video conferencing","Evaluate student progress, adapt methods & build your reputation"]'),
  ('Online Course Creation',              '3–5 months', '["Choose a topic, define learning outcomes & plan curriculum","Write scripts, create slides & record video lessons","Edit content, build quizzes & supplementary materials","Set up on a platform (Udemy, Teachable, Skillshare)","Launch, market your course & iterate based on feedback"]'),
  ('Community Management',                '2–4 months', '["Understand community strategy, goals & platform selection","Set up community spaces: Discord, Slack, forums or Facebook Groups","Create engagement plans: events, discussions & content schedules","Moderate, handle conflicts & nurture community leaders","Measure growth, engagement metrics & report to stakeholders"]'),
  ('Photography',                         '3–5 months', '["Learn camera basics: exposure triangle, composition & light","Practice shooting: portraits, landscapes, street & product","Master post-processing in Lightroom & Photoshop","Develop your style & build a cohesive portfolio","Share work online, find clients & explore specialization"]')
